package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Given
        File out = new File("test.csv");
        Charset charset = Charset.defaultCharset();
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Mock OutputStreamWriter and FileOutputStream
        OutputStreamWriter outputStreamWriter = mock(OutputStreamWriter.class);
        FileOutputStream fileOutputStream = mock(FileOutputStream.class);
        whenNew(OutputStreamWriter.class).withArguments(fileOutputStream, charset).thenReturn(outputStreamWriter);
        whenNew(FileOutputStream.class).withArguments(out).thenReturn(fileOutputStream);

        // When
        CSVPrinter csvPrinter = csvFormat.print(out, charset);

        // Then
        assertNotNull(csvPrinter);
        verifyNew(OutputStreamWriter.class).withArguments(fileOutputStream, charset);
        verifyNew(FileOutputStream.class).withArguments(out);
    }
}
